const t  = $input.first().json.current.temperature_2m;
const at = $input.first().json.current.apparent_temperature;
const h  = $input.first().json.current.relative_humidity_2m;
const d  = $input.first().json.current.is_day === 1 ? 'D' : 'N';
const r  = $input.first().json.current.rain;
const sh = $input.first().json.current.showers;
const sn = $input.first().json.current.snowfall;
const cc = $input.first().json.current.cloud_cover;
const ws = $input.first().json.current.wind_speed_10m;
const wg = $input.first().json.current.wind_gusts_10m;

return [{
  json: {
    toon: `[T:${t}|AT:${at}|H:${h}|D:${d}|R:${r}|SH:${sh}|SN:${sn}|CC:${cc}|WS:${ws}|WG:${wg}]`
  }
}];

return [{
  json: {
    recommendedClothes: $input.first().json.content.parts[0].text,
    weatherConditions: {
      temperature:  $('DatosClima').first().json.current.temperature_2m,
      feelsLike:    $('DatosClima').first().json.current.apparent_temperature,
      humidity:     $('DatosClima').first().json.current.relative_humidity_2m,
      rain:         $('DatosClima').first().json.current.rain,
      showers:      $('DatosClima').first().json.current.showers,
      snowfall:     $('DatosClima').first().json.current.snowfall,
      cloudCover:   $('DatosClima').first().json.current.cloud_cover,
      windSpeed:    $('DatosClima').first().json.current.wind_speed_10m,
      windGusts:    $('DatosClima').first().json.current.wind_gusts_10m,
      isDay:        $('DatosClima').first().json.current.is_day === 1
    },
    temperature: $('DatosClima').first().json.current.temperature_2m
  }
}];
